function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const yCount = new Map<number, number>();
    const yPoints = new Map<number, number[]>();

    for (const [x, y] of points) {
        if (!yCount.has(y)) {
            yCount.set(y, 0);
        }
        yCount.set(y, yCount.get(y)! + 1);
    }

    for (const [x, y] of points) {
        if (!yPoints.has(y)) {
            yPoints.set(y, []);
        }
        yPoints.get(y)!.push(x);
    }

    let result = 0;

    for (const y of yPoints.keys()) {
        const xs = yPoints.get(y)!;
        const n = xs.length;
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                const x1 = xs[i];
                const x2 = xs[j];
                for (const otherY of yCount.keys()) {
                    if (otherY === y) continue;
                    const otherXs = yPoints.get(otherY)!;
                    if (otherXs.length < 2) continue;
                    const m = otherXs.length;
                    const ways = m * (m - 1) / 2;
                    result = (result + ways) % MOD;
                }
            }
        }
    }

    return result;
}
